"use strict";(self.webpackChunkronamosa_github_io=self.webpackChunkronamosa_github_io||[]).push([[56956],{22816:(e,t,o)=>{o.r(t),o.d(t,{assets:()=>u,contentTitle:()=>r,default:()=>d,frontMatter:()=>s,metadata:()=>n,toc:()=>h});var n=o(96787),a=o(74848),i=o(28453);const s={title:"Why I\u2019m Okay With Being the Dumbest Guy on the Team",author:"Ron Amosa",author_title:"Platform Security Engineer @ Salesforce U.S.",author_url:"https://github.com/ronamosa",author_image_url:"https://github.com/ronamosa.png",tags:["career"]},r=void 0,u={authorsImageUrls:[void 0]},h=[];function l(e){const t={blockquote:"blockquote",em:"em",p:"p",...(0,i.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.p,{children:'"Dumbest" is probably a harsh way of putting it.'}),"\n",(0,a.jsx)(t.p,{children:"But I knew I was the least experienced and had the smaller skill-set in a team of battle hardened and really skilled Engineers."}),"\n",(0,a.jsx)(t.p,{children:"I.T. attracts some very smart people and I talk about this in my last post. And sure that doesn't always equal good things. But if you have been fortunate, like me, to end up in a team surrounded by knowledgeable and helpful Engineers (notice I didn't say \"friendly\"), you learn."}),"\n",(0,a.jsx)(t.p,{children:"A lot."}),"\n",(0,a.jsx)(t.p,{children:"Here are some of the key things I learned being the dumbest guy on the team."}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"Ask Questions."}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"Nobody likes being the dumb guy. Asking the \"obvious\" questions. Looking like you don't know your ass from your elbows. But if you've read everything you can, tried to work it out yourself and you still don't know? Ask questions."}),"\n",(0,a.jsx)(t.p,{children:"Like the saying goes \"Ask a question be dumb for 5 minutes, or don't and be dumb forever\". Okay, that's not a direct quote, but you get the gist of what I'm saying."}),"\n",(0,a.jsx)(t.p,{children:"The thing about asking questions when you don't know something (after trying to figure it out yourself) is someone with experience can give you an answer that actually works for you right where you are in the problem."}),"\n",(0,a.jsx)(t.p,{children:"So ask questions. Be a little less dumb."}),"\n",(0,a.jsx)(t.p,{children:"Don't turn up with your questions without having done your homework."}),"\n",(0,a.jsx)(t.p,{children:"And by that I mean, searching for and reading the company's internal documentation. Googling for answers or reading a blog or two. You're demonstrating you're making an effort and aren't there to waste their time."}),"\n",(0,a.jsx)(t.p,{children:'Now, what you consider "looking everywhere" when you first joined the team might have seemed like an exhaustive search. That is until you see their keyword search game and realize your search game is weak sauce and needs improvement so you\'re not sitting here watching them find an answer in front of you in 2 seconds that somehow an hour of searching produced nothing for you.'}),"\n",(0,a.jsx)(t.p,{children:"You could be discouraged, but you have to realize it comes down to experience and knowledge. Wisdom even. These guys have actually used this knowledge out here in the field and know what to look for."}),"\n",(0,a.jsx)(t.p,{children:"Your job is to do the groundwork. Then realize the groundwork is bigger than you expected and adjust your efforts accordingly each time."}),"\n",(0,a.jsx)(t.p,{children:"And why is doing your homework important?"}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"Because time is valuable."}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"This goes two ways."}),"\n",(0,a.jsx)(t.p,{children:"First, the guys I was learning from were on so many simultaneous projects it was crazy. They were doing a couple of big complicated projects along side lots of little fiddly projects and then supporting existing and already BAU projects as well."}),"\n",(0,a.jsxs)(t.p,{children:["Needless to say, they didn't have a lot of time to spare. They don't have time for you being lazy and not doing the groundwork. They don't have time for your b",(0,a.jsx)(t.em,{children:"llsh"}),"t know it all attitude. They don't actually owe you anything and aren't obligated to impart their knowledge to make your life easier."]}),"\n",(0,a.jsx)(t.p,{children:"So if you're going to take up their time, do your best to not waste it. Yes, you're going to ask a lot of \"dumb\" questions at the start. Yes, you're not going to always get the explanation first time. But if you remember and consider the value of the time they give to show you the ropes and point you to key documents, use it and show your appreciation by doing the work so the next question won't be so painful for them."}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"Save yourself time"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"And secondly, if you already get the first point, then this point will make the same sense."}),"\n",(0,a.jsxs)(t.p,{children:["If they can only meet you at 8am, or 430pm, you move ",(0,a.jsx)(t.em,{children:"your"})," thing. You're the new guy and to be quite frank you're not up to speed yet so you're not offering much value at the moment. So if you've got a 'thing' and your more experienced team members need you to move it. Do it."]}),"\n",(0,a.jsx)(t.p,{children:"Why? Because a half an hour with an expert can unravel a complicated system setup and save you...time."}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"Do the work. Even if it means after work hours"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"If you want to be good at this (systems, projects, infrastructure etc), do the work."}),"\n",(0,a.jsx)(t.p,{children:"There are no shortcuts. Even the guys who seem like they picked this up overnight have put in the hours. Reading, experimenting, discussing it with other Engineers."}),"\n",(0,a.jsx)(t.p,{children:"Now it helps if you genuinely geek out on this stuff, but the concept remains the same. Hours, days, years need to be invested. If you want to be good at it."}),"\n",(0,a.jsx)(t.p,{children:"I can be quite competitive. And I also get quite obsessive with solving a problem or understanding a system. So I'll log a lot of hours reading tutorials, reading documentation, setting up and building things in my lab. Just so I know how it works. Or equally, why it doesn't work."}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"Dont take it personally"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"Leave your ego at home. Turn up to learn."}),"\n",(0,a.jsx)(t.p,{children:"If you're told your idea is not a good one, or its flawed and is kind of stupid and not very well thought out - don't take it personally."}),"\n",(0,a.jsx)(t.p,{children:"No-one in my team had a vested interest in making me feel or look stupid. So remembering that even if my team mates didn't think my idea was that great, they would take some time to explain why it wasn't."}),"\n",(0,a.jsx)(t.p,{children:"And I would learn a bit more."}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"Always be the dumbest guy on the team"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"Surround yourself with people you aspire to be like. If you see an opportunity to be in a position where you can learn from skilled Engineers in a field you want to be in - take it."}),"\n",(0,a.jsx)(t.p,{children:"Even if you start at the bottom as a little fish in a big pond (not sure this is the best metaphor, but let's go with it)."}),"\n",(0,a.jsx)(t.p,{children:"What are you learning if you're the big fish in a little pond?"}),"\n",(0,a.jsx)(t.p,{children:"Not much."}),"\n",(0,a.jsx)(t.p,{children:'Putting yourself in a "bottom" position means there\'s only one way to go.'}),"\n",(0,a.jsx)(t.p,{children:"Up."}),"\n",(0,a.jsx)(t.p,{children:"And if you've got the right people around you one day you'll catch up (or get really close)."}),"\n",(0,a.jsx)(t.p,{children:"I started my contracting career because one of these people I look up to called me one day and asked if I wanted to take up a contract. He'd already recommended me to the company."}),"\n",(0,a.jsx)(t.p,{children:"He helped me with the interview, and advised on how to setup to be a contractor. He knew I could do the work because I had done all these things I've just written about. And I had learned from him among others."}),"\n",(0,a.jsx)(t.p,{children:"I wasn't the dumbest guy on the team anymore."}),"\n",(0,a.jsx)(t.p,{children:"I was one of them."}),"\n",(0,a.jsx)(t.p,{children:"...maybe not quite, but a hell of a lot closer than I was before!"})]})}function d(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(l,{...e})}):l(e)}},28453:(e,t,o)=>{o.d(t,{R:()=>s,x:()=>r});var n=o(96540);const a={},i=n.createContext(a);function s(e){const t=n.useContext(i);return n.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),n.createElement(i.Provider,{value:t},e.children)}},96787:e=>{e.exports=JSON.parse('{"permalink":"/blog/2018/03/07/From-Dumbest-Guy-to-Valued-Member","editUrl":"https://github.com/ronamosa/ronamosa.github.io/edit/main/website/blog/2018-03-07-From-Dumbest-Guy-to-Valued-Member.md","source":"@site/blog/2018-03-07-From-Dumbest-Guy-to-Valued-Member.md","title":"Why I\u2019m Okay With Being the Dumbest Guy on the Team","description":"\\"Dumbest\\" is probably a harsh way of putting it.","date":"2018-03-07T00:00:00.000Z","tags":[{"inline":true,"label":"career","permalink":"/blog/tags/career"}],"readingTime":5.67,"hasTruncateMarker":true,"authors":[{"name":"Ron Amosa","title":"Platform Security Engineer @ Salesforce U.S.","url":"https://github.com/ronamosa","imageURL":"https://github.com/ronamosa.png","key":null,"page":null}],"frontMatter":{"title":"Why I\u2019m Okay With Being the Dumbest Guy on the Team","author":"Ron Amosa","author_title":"Platform Security Engineer @ Salesforce U.S.","author_url":"https://github.com/ronamosa","author_image_url":"https://github.com/ronamosa.png","tags":["career"]},"unlisted":false,"prevItem":{"title":"Understanding and Navigating Workplace Stress and When to Get Out","permalink":"/blog/2018/03/10/Understand-Pressure-Stress-Management"},"nextItem":{"title":"How Toxic Egos and Expectations Make For Bad Workplaces","permalink":"/blog/2018/03/06/Egos-Expectations-and-Bad-Workplaces"}}')}}]);